use std::collections::{HashMap, VecDeque};

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }
    if n == 1 {
        return 0;
    }

    const MAX_SIEVE: i64 = 1_000_000;
    let sieve = generate_sieve(MAX_SIEVE);

    let mut value_to_indices = HashMap::new();
    for (idx, &num) in nums.iter().enumerate() {
        value_to_indices.entry(num).or_insert_with(Vec::new).push(idx);
    }

    let max_val = nums.iter().cloned().max().unwrap();

    let mut distance = vec![-1; n];
    distance[0] = 0;
    let mut queue = VecDeque::new();
    queue.push_back(0);

    while let Some(i) = queue.pop_front() {
        if i == n - 1 {
            return distance[i];
        }
        let num_i = nums[i];
        if num_i > 1 && sieve[num_i as usize] {
            let p = num_i;
            let mut m = p;
            while m <= max_val {
                if let Some(indices) = value_to_indices.get(&m) {
                    for &j in indices {
                        if j != i && distance[j] == -1 {
                            distance[j] = distance[i] + 1;
                            queue.push_back(j);
                        }
                    }
                }
                m += p;
            }
        }

        if i > 0 && distance[i - 1] == -1 {
            distance[i - 1] = distance[i] + 1;
            queue.push_back(i - 1);
        }

        if i < n - 1 && distance[i + 1] == -1 {
            distance[i + 1] = distance[i] + 1;
            queue.push_back(i + 1);
        }
    }

    -1
}

fn generate_sieve(max: i64) -> Vec<bool> {
    let max_val = max as usize;
    let mut sieve = vec![true; max_val + 1];
    sieve[0] = false;
    sieve[1] = false;
    for i in 2..=max_val {
        if sieve[i] {
            for j in (i * 2)..=max_val {
                sieve[j] = false;
            }
        }
    }
    sieve
}
